const token = $input.first().json.headers['x-wati-token'];
if (!token || token !== 'CrackTesos2026_WH_Token') {
  return [{json: {ok: 'false'}}];
}
const body = $input.first().json.body;
let phone = (body.phone || '').toString().replace(/[^0-9]/g, '');
if (!phone.startsWith('57') && phone.length === 10) phone = '57' + phone;
if (!phone || phone.length < 10) return [{json: {ok: 'false'}}];
return [{json: {ok: 'true', phone}}];

const rows = $input.all();
if (!rows.length || !rows[0].json.name) {
  return [{json: {
    ok: 'true', encontrado: 'false',
    mensaje: 'No encontramos tu registro en el Crack Tesos. ¿Deseas registrarte?'
  }}];
}
const r = rows[0].json;
const pos = parseInt(r.rank_general || 99999);
let motivacional;
if (pos === 1) motivacional = '¡Estás en el primer lugar! 🥇 ¡Eres el Crack!';
else if (pos <= 3) motivacional = '¡Estás en el podio! 🏆 Sigue así.';
else if (pos <= 10) motivacional = '¡Top 10 nacional! 🔥 Muy cerca de los líderes.';
else if (pos <= parseInt(r.total_participants || 999) * 0.25) motivacional = '¡Buen ritmo! Sigue respondiendo para subir. ⬆️';
else motivacional = '¡Cada trivia es una oportunidad de meter más goles! ⚽';
return [{json: {
  ok: 'true', encontrado: 'true',
  nombre: r.name,
  total_goles: String(r.total_goals || 0),
  rank_general: String(r.rank_general),
  total_participantes: String(r.total_participants),
  agente: r.agent_name || 'Sin asignar',
  rank_agente: String(r.rank_agent),
  total_agente: String(r.total_in_agent),
  trivias_correctas: String(r.correct_count || 0),
  total_respondidas: String(r.total_responses || 0),
  motivacional
}}];
